280→func TestSyncStateRoundTrip(t *testing.T) {
281→	d := setupTestDB(t)
282→	defer d.Close()
283→
284→	engine := NewEngine(d, nil, "")
285→
286→	// Load empty state
287→	state, err := engine.loadSyncState()
288→	if err != nil {
289→		t.Fatal(err)
290→	}
291→	if state.LastPullVersion != 0 || state.LastPushAt != "" {
292→		t.Fatalf("expected empty state, got %+v", state)
293→	}
294→
295→	// Save and reload
296→	state.LastPullVersion = 42
297→	state.LastPushAt = "2026-03-24T10:00:00Z"
298→	if err := engine.saveSyncState(state); err != nil {
299→		t.Fatal(err)
300→	}
301→
302→	loaded, err := engine.loadSyncState()
303→	if err != nil {
304→		t.Fatal(err)
305→	}
306→	if loaded.LastPullVersion != 42 || loaded.LastPushAt != "2026-03-24T10:00:00Z" {
307→		t.Fatalf("state mismatch: %+v", loaded)
308→	}
309→}
