103→// Unipile account callback — called when user completes hosted auth
104→export const unipileAccountCallback = httpAction(async (ctx, request) => {
105→  try {
106→    const payload = await request.json();
107→    const accountId = payload.account_id || "";
108→    const userId = payload.name || ""; // We pass nurge_user_id as 'name'
109→    const email = payload.identifier || "";
