 9→
10→// AuthFile represents the local auth credentials stored at ~/.nurge/auth.json.
11→type AuthFile struct {
12→	Token       string `json:"token"`
13→	Email       string `json:"email"`
14→	Name        string `json:"name"`
15→	CreatedAt   string `json:"created_at,omitempty"`
16→	ValidatedAt string `json:"validated_at,omitempty"`
17→}
18→
19→func authDir() (string, error) {
20→	home, err := os.UserHomeDir()
21→	if err != nil {
22→		return "", fmt.Errorf("getting home directory: %w", err)
23→	}
24→	return filepath.Join(home, ".nurge"), nil
25→}
26→
27→func authFilePath() (string, error) {
28→	dir, err := authDir()
29→	if err != nil {
30→		return "", err
31→	}
32→	return filepath.Join(dir, "auth.json"), nil
33→}
34→
35→// LoadAuth reads the auth file from ~/.nurge/auth.json.
36→func LoadAuth() (*AuthFile, error) {
37→	path, err := authFilePath()
38→	if err != nil {
39→		return nil, err
40→	}
41→	data, err := os.ReadFile(path)
42→	if err != nil {
43→		return nil, fmt.Errorf("reading auth file: %w", err)
44→	}
45→	var af AuthFile
46→	if err := json.Unmarshal(data, &af); err != nil {
47→		return nil, fmt.Errorf("parsing auth file: %w", err)
48→	}
49→	return &af, nil
