51→
52→// SaveAuth writes the auth file to ~/.nurge/auth.json.
53→// Creates ~/.nurge/ with 0700 if it doesn't exist.
54→// Writes auth.json with 0600 permissions.
55→func SaveAuth(af *AuthFile) error {
56→	dir, err := authDir()
57→	if err != nil {
58→		return err
59→	}
60→	if err := os.MkdirAll(dir, 0700); err != nil {
61→		return fmt.Errorf("creating auth directory: %w", err)
62→	}
63→
64→	data, err := json.MarshalIndent(af, "", "  ")
65→	if err != nil {
66→		return fmt.Errorf("marshaling auth file: %w", err)
67→	}
68→
69→	path := filepath.Join(dir, "auth.json")
70→	if err := os.WriteFile(path, data, 0600); err != nil {
71→		return fmt.Errorf("writing auth file: %w", err)
72→	}
73→	return nil
74→}
75→
76→// DeleteAuth removes ~/.nurge/auth.json.
77→func DeleteAuth() error {
78→	path, err := authFilePath()
79→	if err != nil {
80→		return err
81→	}
82→	if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
83→		return fmt.Errorf("deleting auth file: %w", err)
84→	}
85→	return nil
86→}
