package cmd

import (
	"encoding/json"
	"fmt"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/account"
)

var accountFormat string

var accountCmd = &cobra.Command{
	Use:         "account",
	Short:       "Show account status",
	Annotations: map[string]string{"skipAuth": "true"},
	RunE: func(cmd *cobra.Command, args []string) error {
		af, err := account.LoadAuth()
		if err != nil {
			if accountFormat == "json" {
				data, _ := json.Marshal(map[string]any{"logged_in": false})
				fmt.Println(string(data))
				return nil
			}
			fmt.Fprintln(os.Stderr, "  Not logged in. Run `nurge account login` to authenticate.")
			return nil
		}

		if accountFormat == "json" {
			data, _ := json.Marshal(map[string]any{
				"logged_in": true,
				"email":     af.Email,
				"name":      af.Name,
			})
			fmt.Println(string(data))
			return nil
		}

		fmt.Fprintf(os.Stderr, "  Logged in as %s (%s)\n", af.Name, af.Email)
		return nil
	},
}

var accountLoginCmd = &cobra.Command{
	Use:         "login",
	Short:       "Log in to your nurge account",
	Annotations: map[string]string{"skipAuth": "true"},
	RunE: func(cmd *cobra.Command, args []string) error {
		_, err := account.Login(GetConvexURL(), GetDashboardURL())
		return err
	},
}

var accountLogoutCmd = &cobra.Command{
	Use:         "logout",
	Short:       "Log out of your nurge account",
	Annotations: map[string]string{"skipAuth": "true"},
	RunE: func(cmd *cobra.Command, args []string) error {
		return account.Logout(GetConvexURL())
	},
}

