720→export const markTaskFailed = internalMutation({
721→  args: {
722→    userId: v.string(),
723→    taskId: v.string(),
724→    error: v.string(),
725→    authError: v.boolean(),
726→    mailboxId: v.string(),
727→  },
728→  handler: async (ctx, args) => {
729→    const task = await ctx.db
730→      .query("followUpTasks")
731→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
732→      .first();
733→    if (!task) return;
734→
735→    const syncState = await ctx.db
736→      .query("syncState")
737→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
738→      .first();
739→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
740→
741→    const newAttemptCount = task.attemptCount + 1;
742→
743→    await ctx.db.patch(task._id, {
744→      sendStatus: args.authError ? "failed" : "pending", // auth errors don't retry
745→      lastAttemptAt: new Date().toISOString(),
746→      lastError: args.error,
747→      attemptCount: newAttemptCount,
748→      syncVersion: version,
749→    });
750→
751→    // Mark mailbox auth_expired on auth errors
752→    if (args.authError && args.mailboxId) {
753→      const mailbox = await ctx.db
754→        .query("mailboxes")
755→        .withIndex("by_external_id", (q) => q.eq("externalId", args.mailboxId))
756→        .first();
757→      if (mailbox) {
758→        version++;
759→        await ctx.db.patch(mailbox._id, {
760→          status: "auth_expired",
761→          syncVersion: version,
762→        });
763→      }
764→    }
765→
766→    if (syncState) {
767→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
768→    } else {
769→      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
770→    }
771→  },
772→});
