 73→// Count sends for a mailbox on a given day for a specific send type.
 74→export async function countSendsForDay(
 75→  ctx: QueryCtx,
 76→  mailboxId: string,
 77→  sendType: string,
 78→  dayStr: string // YYYY-MM-DD
 79→): Promise<number> {
 80→  const events = await ctx.db
 81→    .query("mailboxSendEvents")
 82→    .withIndex("by_mailbox_day", (q) =>
 83→      q.eq("mailboxId", mailboxId).gte("sentAt", dayStr + "T00:00:00Z").lte("sentAt", dayStr + "T23:59:59Z")
 84→    )
 85→    .collect();
 86→
 87→  return events.filter((e) => e.sendType === sendType).length;
 88→}
