	// We just need the payload (middle part) for email/name
	parts := splitJWT(idToken)
	if len(parts) != 3 {
		return "", "", fmt.Errorf("invalid id_token format")
	}

	payload, err := base64URLDecode(parts[1])
	if err != nil {
		return "", "", fmt.Errorf("decoding id_token payload: %w", err)
	}

	var claims struct {
		Email string `json:"email"`
		Name  string `json:"name"`
	}
	if err := json.Unmarshal(payload, &claims); err != nil {
		return "", "", fmt.Errorf("parsing id_token claims: %w", err)
	}

	return claims.Email, claims.Name, nil
}

func splitJWT(token string) []string {
	var parts []string
	start := 0
	for i := 0; i < len(token); i++ {
		if token[i] == '.' {
			parts = append(parts, token[start:i])
			start = i + 1
		}
	}
	parts = append(parts, token[start:])
	return parts
}

func base64URLDecode(s string) ([]byte, error) {
	// Add padding if needed
	switch len(s) % 4 {
	case 2:
		s += "=="
	case 3:
		s += "="
	}

	// Use standard base64 with URL-safe alphabet
	import_encoding := make([]byte, len(s))
	copy(import_encoding, s)
	// Replace URL-safe chars with standard base64 chars
	for i := range import_encoding {
		switch import_encoding[i] {
		case '-':
			import_encoding[i] = '+'
		case '_':
			import_encoding[i] = '/'
		}
	}

	// Use encoding/base64
	var decoded []byte
	decoded, err := base64Decode(string(import_encoding))
	return decoded, err
}

