package account

import (
	"bytes"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"time"
)

// User represents an authenticated Nurge user.
type User struct {
	Email string `json:"email"`
	Name  string `json:"name"`
}

// ConvexClient calls Convex HTTP actions for auth operations.
type ConvexClient struct {
	baseURL    string
	httpClient *http.Client
}

// NewConvexClient creates a client for the given Convex site URL.
func NewConvexClient(baseURL string) *ConvexClient {
	return &ConvexClient{
		baseURL: baseURL,
		httpClient: &http.Client{
			Timeout: 10 * time.Second,
		},
	}
}

type validateResponse struct {
	Valid bool  `json:"valid"`
	User  *User `json:"user,omitempty"`
}

// ErrTokenInvalid is returned when the server confirms the token is invalid.
// This is distinct from network errors, which may allow grace period fallback.
var ErrTokenInvalid = errors.New("token is invalid or expired")

// ValidateToken checks a token against the Convex backend.
// Returns ErrTokenInvalid if server says token is invalid.
// Returns a different error for network/parse failures.
func (c *ConvexClient) ValidateToken(token string) (*User, error) {
	body, err := json.Marshal(map[string]string{"token": token})
	if err != nil {
		return nil, fmt.Errorf("marshaling request: %w", err)
	}
	resp, err := c.httpClient.Post(
		c.baseURL+"/api/validate-token",
		"application/json",
		bytes.NewReader(body),
	)
	if err != nil {
		return nil, fmt.Errorf("calling validate-token: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	var result validateResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing response: %w", err)
	}

	if !result.Valid {
		return nil, ErrTokenInvalid
	}
	return result.User, nil
}

type exchangeResponse struct {
	Token string `json:"token"`
	Email string `json:"email"`
	Name  string `json:"name"`
	Error string `json:"error,omitempty"`
}

// ExchangeCode exchanges a one-time auth code for an API token.
func (c *ConvexClient) ExchangeCode(code string) (*exchangeResponse, error) {
	body, _ := json.Marshal(map[string]string{"code": code})
	resp, err := c.httpClient.Post(
		c.baseURL+"/api/exchange-code",
		"application/json",
		bytes.NewReader(body),
	)
	if err != nil {
		return nil, fmt.Errorf("calling exchange-code: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	if resp.StatusCode != 200 {
		var errResp struct {
			Error string `json:"error"`
		}
		json.Unmarshal(data, &errResp)
		return nil, fmt.Errorf("exchange failed: %s", errResp.Error)
	}

	var result exchangeResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing response: %w", err)
	}
	return &result, nil
}

// SendEmailRequest is the payload for the /api/send-email endpoint.
type SendEmailRequest struct {
	To       string           `json:"to"`
	Cc       string           `json:"cc,omitempty"`
	Subject  string           `json:"subject"`
	Body     string           `json:"body"`
	SendType string           `json:"sendType"`
	Sync     bool             `json:"sync"`
	TaskID   string           `json:"taskId,omitempty"`
	Sequence *SequenceRequest `json:"sequence,omitempty"`
}

// SequenceRequest defines sequence enrollment details for a send.
type SequenceRequest struct {
	SequenceName string         `json:"sequenceName"`
	CampaignName string         `json:"campaignName,omitempty"`
	ContactName  string         `json:"contactName,omitempty"`
	MailboxID    string         `json:"mailboxId,omitempty"`
	Steps        []SequenceStep `json:"steps,omitempty"`
}

// SequenceStep defines a future step in a sequence.
type SequenceStep struct {
	StepNumber int    `json:"stepNumber"`
	StepName   string `json:"stepName,omitempty"`
	SendType   string `json:"sendType"`
	DelayDays  int    `json:"delayDays"`
	Subject    string `json:"subject,omitempty"`
	Body       string `json:"body,omitempty"`
}

// SendEmailResponse is the response from the /api/send-email endpoint.
type SendEmailResponse struct {
	OK           bool   `json:"ok"`
	Queued       bool   `json:"queued,omitempty"`
	MessageID    string `json:"messageId,omitempty"`
	ProviderID   string `json:"providerId,omitempty"`
	EnrollmentID string `json:"enrollmentId,omitempty"`
	TaskID       string `json:"taskId,omitempty"`
	Error        string `json:"error,omitempty"`
}

// SendEmail calls the Convex /api/send-email endpoint.
func (c *ConvexClient) SendEmail(token string, req SendEmailRequest) (*SendEmailResponse, error) {
	body, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("marshaling request: %w", err)
	}

	httpReq, err := http.NewRequest("POST", c.baseURL+"/api/send-email", bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("creating request: %w", err)
	}
	httpReq.Header.Set("Content-Type", "application/json")
	httpReq.Header.Set("Authorization", "Bearer "+token)

	resp, err := c.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("calling send-email: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	var result SendEmailResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing response: %w", err)
	}

	if !result.OK {
		return &result, fmt.Errorf("%s", result.Error)
	}
	return &result, nil
}

// RevokeToken revokes a token on the Convex backend.
func (c *ConvexClient) RevokeToken(token string) error {
	body, _ := json.Marshal(map[string]string{"token": token})
	resp, err := c.httpClient.Post(
		c.baseURL+"/api/revoke-token",
		"application/json",
		bytes.NewReader(body),
	)
	if err != nil {
		return fmt.Errorf("calling revoke-token: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		return fmt.Errorf("revoke failed with status %d", resp.StatusCode)
	}
	return nil
}

